%% =========================================================================
% P4_Exp05_fixed_scale_NMC_k_regret_benchmark.m
%
% Purpose:
% This script quantifies the cost regret of non-optimal SOH-label sizes
% under the fixed-scale NMC recertification setting.
%
% It reads the fixed-scale NMC optimization results generated by Part4
% Exp02, where each k has already been paired with its own optimized
% thresholds T1 and T2. The script then computes the additional cost caused
% by choosing each non-optimal k relative to the fixed-scale optimum k*.
%
% Output figure:
% Extended Data Fig. 6b.

clear; clc; close all;

set(groot, 'DefaultFigureVisible', 'on');

%% 0. Path configuration

cfg = struct();

script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
    script_dir = pwd;
end

% Part4 folders.
cfg.output_dir = fullfile(script_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.figure_root = fullfile(script_dir, 'Figures');
cfg.main_fig_dir = fullfile(cfg.figure_root, 'Main');
cfg.extended_fig_dir = fullfile(cfg.figure_root, 'Extended');

% Primary input generated by Part4 Exp02.
cfg.nmc_result_primary = fullfile(cfg.results_dir, ...
    'P4_Exp02_FixedScale_NMC_Results.mat');

% Legacy result fallback.
cfg.nmc_result_legacy = fullfile(cfg.output_dir, ...
    'Result02_FixedScale_NMC_Results.mat');

% Workspace fallbacks.
cfg.nmc_workspace_primary = fullfile(cfg.results_dir, ...
    'P4_Exp02_FixedScale_NMC_Workspace.mat');

cfg.nmc_workspace_legacy = fullfile(cfg.output_dir, ...
    'Result02_FixedScale_NMC_Workspace.mat');

% Output data files.
cfg.result_mat = fullfile(cfg.results_dir, ...
    'P4_Exp05_FixedScale_NMC_KRegretBenchmark_Results.mat');

cfg.curve_csv = fullfile(cfg.results_dir, ...
    'P4_Exp05_FixedScale_NMC_KRegretBenchmark_Curve.csv');

cfg.scenario_csv = fullfile(cfg.results_dir, ...
    'P4_Exp05_FixedScale_NMC_KRegretBenchmark_Scenarios.csv');

% Extended Data Fig. 6b output.
cfg.fig_regret = fullfile(cfg.extended_fig_dir, ...
    'ExD06b_NMC_FixedScale_KRegretBenchmark.fig');

cfg.png_regret = fullfile(cfg.extended_fig_dir, ...
    'ExD06b_NMC_FixedScale_KRegretBenchmark.png');

cfg.png_resolution = 600;

% Create required folders.
folder_list = { ...
    cfg.output_dir, ...
    cfg.results_dir, ...
    cfg.figure_root, ...
    cfg.main_fig_dir, ...
    cfg.extended_fig_dir};

for ii = 1:numel(folder_list)
    if ~exist(folder_list{ii}, 'dir')
        mkdir(folder_list{ii});
    end
end

%% 1. Locate fixed-scale NMC result file

if isfile(cfg.nmc_result_primary)

    cfg.input_file = cfg.nmc_result_primary;
    cfg.input_type = 'structured_result';

elseif isfile(cfg.nmc_result_legacy)

    cfg.input_file = cfg.nmc_result_legacy;
    cfg.input_type = 'structured_result';

elseif isfile(cfg.nmc_workspace_primary)

    cfg.input_file = cfg.nmc_workspace_primary;
    cfg.input_type = 'workspace';

elseif isfile(cfg.nmc_workspace_legacy)

    cfg.input_file = cfg.nmc_workspace_legacy;
    cfg.input_type = 'workspace';

else

    error(['Fixed-scale NMC result or workspace file not found.\n' ...
        'Checked:\n%s\n%s\n%s\n%s\n' ...
        'Please run Part4 Exp02 first.'], ...
        cfg.nmc_result_primary, ...
        cfg.nmc_result_legacy, ...
        cfg.nmc_workspace_primary, ...
        cfg.nmc_workspace_legacy);
end

fprintf('================ Part4 Exp05 fixed-scale NMC k-regret benchmark ================\n');
fprintf('Input file:            %s\n', cfg.input_file);
fprintf('Input type:            %s\n', cfg.input_type);
fprintf('Curve CSV:             %s\n', cfg.curve_csv);
fprintf('Scenario CSV:          %s\n', cfg.scenario_csv);
fprintf('Result MAT:            %s\n', cfg.result_mat);
fprintf('Extended figure file:  %s\n', cfg.png_regret);

%% 2. Load fixed-scale NMC optimization results

S = load(cfg.input_file);

if isfield(S, 'NMC_fixed_result')

    R = S.NMC_fixed_result;

else

    % Workspace-style fallback.
    R = S;
end

required_fields = { ...
    'Fixed_Scale_N', ...
    'k_vals', ...
    'Fixed_Total_Cost', ...
    'Fixed_O', ...
    'Fixed_A', ...
    'Fixed_R', ...
    'Fixed_Model', ...
    'T1_base', ...
    'T2_base'};

for ii = 1:numel(required_fields)

    field_now = required_fields{ii};

    if ~isfield(R, field_now)
        error('Required field is missing from the fixed-scale NMC result: %s', ...
            field_now);
    end
end

Fixed_Scale_N = double(R.Fixed_Scale_N);
k_vals = double(R.k_vals(:));

Fixed_Total_Cost = double(R.Fixed_Total_Cost(:));
Fixed_O = double(R.Fixed_O(:));
Fixed_A = double(R.Fixed_A(:));
Fixed_R = double(R.Fixed_R(:));
Fixed_Model = double(R.Fixed_Model(:));

T1_base = double(R.T1_base(:));
T2_base = double(R.T2_base(:));

num_k = numel(k_vals);

if any([ ...
        numel(Fixed_Total_Cost), ...
        numel(Fixed_O), ...
        numel(Fixed_A), ...
        numel(Fixed_R), ...
        numel(Fixed_Model), ...
        numel(T1_base), ...
        numel(T2_base)] ~= num_k)

    error('The lengths of k-dependent fixed-scale arrays are inconsistent.');
end

% Recompute the fixed-scale optimum from the loaded cost curve to avoid
% relying on stale saved indices.
[C_star, opt_k_idx] = min(Fixed_Total_Cost);
opt_k = k_vals(opt_k_idx);
opt_T1 = T1_base(opt_k_idx);
opt_T2 = T2_base(opt_k_idx);
c_star_per_pack = C_star / Fixed_Scale_N;

fprintf('>>> Fixed-scale NMC result loaded.\n');
fprintf('>>> Fixed_Scale_N = %d packs.\n', Fixed_Scale_N);
fprintf('>>> k range = %d to %d.\n', min(k_vals), max(k_vals));
fprintf('>>> Optimal k* = %d, T1* = %.4f, T2* = %.4f.\n', ...
    opt_k, opt_T1, opt_T2);
fprintf('>>> Optimal total cost = %.4f USD.\n', C_star);
fprintf('>>> Optimal per-pack cost = %.4f USD per pack.\n', c_star_per_pack);

%% 3. Compute k-dependent cost regret

Cost_per_pack = Fixed_Total_Cost ./ Fixed_Scale_N;

Regret_total_USD = Fixed_Total_Cost - C_star;
Regret_per_pack_USD = Regret_total_USD ./ Fixed_Scale_N;

Relative_excess_to_optimum_percent = 100 .* Regret_total_USD ./ max(C_star, eps);
Cost_saving_from_optimum_vs_policy_percent = ...
    100 .* Regret_total_USD ./ max(Fixed_Total_Cost, eps);

% Numerical cleanup around the optimum.
Regret_total_USD(abs(Regret_total_USD) < 1e-9) = 0;
Regret_per_pack_USD(abs(Regret_per_pack_USD) < 1e-12) = 0;
Relative_excess_to_optimum_percent(abs(Relative_excess_to_optimum_percent) < 1e-10) = 0;
Cost_saving_from_optimum_vs_policy_percent(abs(Cost_saving_from_optimum_vs_policy_percent) < 1e-10) = 0;

KRegret_Curve_Table = table( ...
    k_vals, ...
    T1_base, ...
    T2_base, ...
    Fixed_Total_Cost, ...
    Cost_per_pack, ...
    Fixed_O, ...
    Fixed_A, ...
    Fixed_R, ...
    Fixed_Model, ...
    Regret_total_USD, ...
    Regret_per_pack_USD, ...
    Relative_excess_to_optimum_percent, ...
    Cost_saving_from_optimum_vs_policy_percent, ...
    'VariableNames', { ...
    'k', ...
    'T1_star_given_k', ...
    'T2_star_given_k', ...
    'Total_cost_USD', ...
    'Cost_per_pack_USD', ...
    'Opportunity_loss_USD', ...
    'Manual_review_cost_USD', ...
    'Risk_penalty_USD', ...
    'SOH_labeling_training_cost_USD', ...
    'Cost_regret_USD', ...
    'Cost_regret_per_pack_USD', ...
    'Excess_cost_relative_to_optimum_percent', ...
    'Cost_saving_from_optimum_vs_policy_percent'});

writetable(KRegret_Curve_Table, cfg.curve_csv);

fprintf('>>> k-regret curve table saved: %s\n', cfg.curve_csv);

%% 4. Extract representative fixed-k benchmark scenarios

benchmark_k_target =  opt_k;
benchmark_k_target = unique(benchmark_k_target, 'stable');

n_benchmark = numel(benchmark_k_target);

Scenario_label = strings(n_benchmark, 1);
Benchmark_k_target = zeros(n_benchmark, 1);
Benchmark_k_actual = zeros(n_benchmark, 1);
Benchmark_k_idx = zeros(n_benchmark, 1);
Is_exact_k_match = false(n_benchmark, 1);
Is_optimized_policy = false(n_benchmark, 1);

Scenario_T1 = zeros(n_benchmark, 1);
Scenario_T2 = zeros(n_benchmark, 1);

Scenario_total_cost_USD = zeros(n_benchmark, 1);
Scenario_cost_per_pack_USD = zeros(n_benchmark, 1);

Scenario_O_USD = zeros(n_benchmark, 1);
Scenario_A_USD = zeros(n_benchmark, 1);
Scenario_R_USD = zeros(n_benchmark, 1);
Scenario_Model_USD = zeros(n_benchmark, 1);

Scenario_regret_USD = zeros(n_benchmark, 1);
Scenario_regret_per_pack_USD = zeros(n_benchmark, 1);
Scenario_excess_to_optimum_percent = zeros(n_benchmark, 1);
Scenario_saving_from_optimum_percent = zeros(n_benchmark, 1);

for ii = 1:n_benchmark

    k_target = benchmark_k_target(ii);

    idx_exact = find(k_vals == k_target, 1, 'first');

    if isempty(idx_exact)
        [~, idx_now] = min(abs(k_vals - k_target));
        is_exact = false;
    else
        idx_now = idx_exact;
        is_exact = true;
    end

    k_actual = k_vals(idx_now);

    Benchmark_k_target(ii) = k_target;
    Benchmark_k_actual(ii) = k_actual;
    Benchmark_k_idx(ii) = idx_now;
    Is_exact_k_match(ii) = is_exact;
    Is_optimized_policy(ii) = (idx_now == opt_k_idx);

    if idx_now == opt_k_idx && ismember(k_actual, [5, 25, 50])
        Scenario_label(ii) = sprintf('Fixed k = %d / optimized k*', k_actual);
    elseif idx_now == opt_k_idx
        Scenario_label(ii) = sprintf('Optimized k* = %d', k_actual);
    elseif k_target == 5
        Scenario_label(ii) = 'Minimum-information fixed k = 5';
    elseif k_target == 25
        Scenario_label(ii) = 'Moderate fixed k = 25';
    elseif k_target == 50
        Scenario_label(ii) = 'High-information fixed k = 50';
    else
        Scenario_label(ii) = sprintf('Fixed k = %d', k_actual);
    end

    Scenario_T1(ii) = T1_base(idx_now);
    Scenario_T2(ii) = T2_base(idx_now);

    Scenario_total_cost_USD(ii) = Fixed_Total_Cost(idx_now);
    Scenario_cost_per_pack_USD(ii) = Cost_per_pack(idx_now);

    Scenario_O_USD(ii) = Fixed_O(idx_now);
    Scenario_A_USD(ii) = Fixed_A(idx_now);
    Scenario_R_USD(ii) = Fixed_R(idx_now);
    Scenario_Model_USD(ii) = Fixed_Model(idx_now);

    Scenario_regret_USD(ii) = Regret_total_USD(idx_now);
    Scenario_regret_per_pack_USD(ii) = Regret_per_pack_USD(idx_now);

    Scenario_excess_to_optimum_percent(ii) = ...
        Relative_excess_to_optimum_percent(idx_now);

    Scenario_saving_from_optimum_percent(ii) = ...
        Cost_saving_from_optimum_vs_policy_percent(idx_now);
end

KRegret_Scenario_Table = table( ...
    Scenario_label, ...
    Benchmark_k_target, ...
    Benchmark_k_actual, ...
    Benchmark_k_idx, ...
    Is_exact_k_match, ...
    Is_optimized_policy, ...
    Scenario_T1, ...
    Scenario_T2, ...
    Scenario_total_cost_USD, ...
    Scenario_cost_per_pack_USD, ...
    Scenario_O_USD, ...
    Scenario_A_USD, ...
    Scenario_R_USD, ...
    Scenario_Model_USD, ...
    Scenario_regret_USD, ...
    Scenario_regret_per_pack_USD, ...
    Scenario_excess_to_optimum_percent, ...
    Scenario_saving_from_optimum_percent, ...
    'VariableNames', { ...
    'Scenario_label', ...
    'Target_k', ...
    'Actual_k', ...
    'k_index', ...
    'Exact_k_match', ...
    'Is_optimized_policy', ...
    'T1_star_given_k', ...
    'T2_star_given_k', ...
    'Total_cost_USD', ...
    'Cost_per_pack_USD', ...
    'Opportunity_loss_USD', ...
    'Manual_review_cost_USD', ...
    'Risk_penalty_USD', ...
    'SOH_labeling_training_cost_USD', ...
    'Cost_regret_USD', ...
    'Cost_regret_per_pack_USD', ...
    'Excess_cost_relative_to_optimum_percent', ...
    'Cost_saving_from_optimum_vs_policy_percent'});

writetable(KRegret_Scenario_Table, cfg.scenario_csv);

fprintf('>>> Representative scenario table saved: %s\n', cfg.scenario_csv);

disp(' ');
disp('========== Fixed-scale NMC k-regret benchmark scenarios ==========');
disp(KRegret_Scenario_Table);

%% 5. Plot fixed-scale k-regret curve

fig_regret = figure('Name', 'ExD Fig. 6b - NMC fixed-scale k-regret benchmark', ...
    'Color', 'w', ...
    'Position', [120, 120, 760, 540]);

hold on;

plot(k_vals, Regret_per_pack_USD, ...
    '-k', ...
    'LineWidth', 2.2);

scatter(k_vals, Regret_per_pack_USD, ...
    32, ...
    'o', ...
    'MarkerFaceColor', [0.90, 0.90, 0.90], ...
    'MarkerEdgeColor', [0.20, 0.20, 0.20], ...
    'LineWidth', 0.8);


% Highlight the optimized policy.
scatter(opt_k, Regret_per_pack_USD(opt_k_idx), ...
    150, ...
    'p', ...
    'MarkerFaceColor', [0.85, 0.20, 0.20], ...
    'MarkerEdgeColor', 'k', ...
    'LineWidth', 1.0);

xline(opt_k, ...
    '--', ...
    'Color', [0.85, 0.20, 0.20], ...
    'LineWidth', 1.2, ...
    'HandleVisibility', 'off');

text(opt_k, max(Regret_per_pack_USD) * 0.08, ...
    sprintf('  k^* = %d', opt_k), ...
    'FontName', 'Arial', ...
    'FontSize', 11, ...
    'Color', [0.70, 0.05, 0.05], ...
    'VerticalAlignment', 'bottom');

grid on;
box on;

xlabel('SOH label size, k');
ylabel('Cost regret relative to optimized policy (USD per pack)');
title('Fixed-scale NMC cost regret from non-optimal SOH-label investment');

set(gca, ...
    'FontName', 'Arial', ...
    'FontSize', 12, ...
    'LineWidth', 1.0);

xlim([min(k_vals), max(k_vals)]);

ymax = max(Regret_per_pack_USD);

if ymax <= 0
    ymax = 1;
end

ylim([0, ymax * 1.12]);

hold off;

savefig(fig_regret, cfg.fig_regret);

exportgraphics(fig_regret, cfg.png_regret, ...
    'Resolution', cfg.png_resolution);

fprintf('>>> Fixed-scale NMC k-regret figure saved: %s\n', cfg.png_regret);

%% 6. Save result MAT file

NMC_KRegretBenchmark_Result = struct();

NMC_KRegretBenchmark_Result.Fixed_Scale_N = Fixed_Scale_N;
NMC_KRegretBenchmark_Result.k_vals = k_vals;

NMC_KRegretBenchmark_Result.Fixed_Total_Cost = Fixed_Total_Cost;
NMC_KRegretBenchmark_Result.Cost_per_pack = Cost_per_pack;

NMC_KRegretBenchmark_Result.Fixed_O = Fixed_O;
NMC_KRegretBenchmark_Result.Fixed_A = Fixed_A;
NMC_KRegretBenchmark_Result.Fixed_R = Fixed_R;
NMC_KRegretBenchmark_Result.Fixed_Model = Fixed_Model;

NMC_KRegretBenchmark_Result.T1_base = T1_base;
NMC_KRegretBenchmark_Result.T2_base = T2_base;

NMC_KRegretBenchmark_Result.opt_k_idx = opt_k_idx;
NMC_KRegretBenchmark_Result.opt_k = opt_k;
NMC_KRegretBenchmark_Result.opt_T1 = opt_T1;
NMC_KRegretBenchmark_Result.opt_T2 = opt_T2;
NMC_KRegretBenchmark_Result.opt_total_cost_USD = C_star;
NMC_KRegretBenchmark_Result.opt_cost_per_pack_USD = c_star_per_pack;

NMC_KRegretBenchmark_Result.Regret_total_USD = Regret_total_USD;
NMC_KRegretBenchmark_Result.Regret_per_pack_USD = Regret_per_pack_USD;
NMC_KRegretBenchmark_Result.Relative_excess_to_optimum_percent = ...
    Relative_excess_to_optimum_percent;
NMC_KRegretBenchmark_Result.Cost_saving_from_optimum_vs_policy_percent = ...
    Cost_saving_from_optimum_vs_policy_percent;

NMC_KRegretBenchmark_Result.KRegret_Curve_Table = KRegret_Curve_Table;
NMC_KRegretBenchmark_Result.KRegret_Scenario_Table = KRegret_Scenario_Table;

NMC_KRegretBenchmark_Result.input_file = cfg.input_file;
NMC_KRegretBenchmark_Result.cfg_part4_exp05 = cfg;

save(cfg.result_mat, ...
    'NMC_KRegretBenchmark_Result', ...
    'KRegret_Curve_Table', ...
    'KRegret_Scenario_Table', ...
    '-v7.3');

fprintf('>>> Fixed-scale NMC k-regret benchmark result saved: %s\n', cfg.result_mat);
fprintf('================ Part4 Exp05 completed ================\n');